import numpy as np
from collections import deque

def get_components_8(grid):
    """Find 8-connected components of non-zero cells"""
    H, W = grid.shape
    visited = np.zeros_like(grid, dtype=bool)
    components = []

    for r in range(H):
        for c in range(W):
            if grid[r,c] != 0 and not visited[r,c]:
                # BFS
                comp = []
                q = deque([(r,c)])
                visited[r,c] = True
                while q:
                    cr, cc = q.popleft()
                    comp.append((cr, cc, int(grid[cr,cc])))
                    for dr in [-1,0,1]:
                        for dc in [-1,0,1]:
                            if dr == 0 and dc == 0: continue
                            nr, nc = cr+dr, cc+dc
                            if 0 <= nr < H and 0 <= nc < W and not visited[nr,nc] and grid[nr,nc] != 0:
                                visited[nr,nc] = True
                                q.append((nr,nc))
                components.append(comp)
    return components

