import numpy as np
from collections import deque

def find_graph_vertex(primary_cells):
    """For path-like shapes, find the vertex (point of max direction change)"""
    if len(primary_cells) < 3:
        return None

    cell_set = set(primary_cells)

    # Build adjacency (8-connected among primary cells only)
    adj = {c: [] for c in primary_cells}
    for r, c in primary_cells:
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                if dr == 0 and dc == 0:
                    continue
                nr, nc = r + dr, c + dc
                if (nr, nc) in cell_set:
                    adj[(r,c)].append((nr, nc))

    # Find degree of each node
    degrees = {c: len(adj[c]) for c in primary_cells}

    # Find endpoints (degree 1)
    endpoints = [c for c in primary_cells if degrees[c] == 1]

    # Case 1: Simple path with exactly 2 endpoints
    if len(endpoints) == 2:
        # Trace the path and find the point of max direction change
        start = endpoints[0]
        path = [start]
        visited = {start}
        curr = start
        while True:
            next_cells = [n for n in adj[curr] if n not in visited]
            if not next_cells:
                break
            # For path (degree ≤ 2), there should be at most 1 unvisited neighbor
            curr = next_cells[0]
            path.append(curr)
            visited.add(curr)

        if len(path) >= 3:
            # Find point of maximum direction change
            max_change = 0
            vertex = None
            for i in range(1, len(path) - 1):
                d1 = (path[i][0] - path[i-1][0], path[i][1] - path[i-1][1])
                d2 = (path[i+1][0] - path[i][0], path[i+1][1] - path[i][1])
                change = abs(d1[0] - d2[0]) + abs(d1[1] - d2[1])
                if change > max_change:
                    max_change = change
                    vertex = path[i]

            if max_change > 0:
                return vertex

    # Case 2: Y-shape with 3 endpoints
    if len(endpoints) == 3:
        # Find branching point (degree >= 3)
        branch_points = [c for c in primary_cells if degrees[c] >= 3]
        if branch_points:
            bp = branch_points[0]
            # Find arm lengths from branching point to each endpoint
            arms = []
            for ep in endpoints:
                # BFS from bp to ep
                q = deque([(bp, 0)])
                vis = {bp}
                dist = -1
                while q:
                    node, d = q.popleft()
                    if node == ep:
                        dist = d
                        break
                    for n in adj[node]:
                        if n not in vis:
                            vis.add(n)
                            q.append((n, d + 1))
                arms.append((dist, ep))

            # Tip is the endpoint of the shortest arm
            arms.sort()
            return arms[0][1]

    return None

# Test vertex detection on training examples
for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    comps = get_components_8(inp)

    for j, comp in enumerate(comps):
        colors = {}
        for r,c,v in comp:
            colors[v] = colors.get(v, 0) + 1

        if len(colors) != 2:
            continue

        sorted_colors = sorted(colors.items(), key=lambda x: x[1], reverse=True)
        primary_color = sorted_colors[0][0]
        primary_cells = [(r,c) for r,c,v in comp if v == primary_color]

        vertex = find_graph_vertex(primary_cells)
        print(f"Example {i}, Component {j}: vertex={vertex}, primary_cells={sorted(primary_cells)}")

